const wfs = $input.first().json.workflows || [];
const statusBadge = s => {
  if (s === 'ok') return '<span style="background:#10b981;color:white;padding:1px 8px;border-radius:3px;font-size:10px">OK</span>';
  if (s === 'never_run') return '<span style="background:#3b82f6;color:white;padding:1px 8px;border-radius:3px;font-size:10px">NEVER</span>';
  if (s === 'no_log_action') return '<span style="background:#6b7280;color:white;padding:1px 8px;border-radius:3px;font-size:10px">NO_TRACK</span>';
  return '<span style="background:#dc2626;color:white;padding:1px 8px;border-radius:3px;font-size:10px">STALE</span>';
};
const row = (cells) => '<tr>'+cells.map(c=>'<td style="padding:8px;border-bottom:1px solid #eee;font-size:12px">'+c+'</td>').join('')+'</tr>';
const stale = wfs.filter(w => w.status === 'stale' || w.status === 'never_run');
const rows = wfs.map(w => row([
  '<b>'+w.workflow_name+'</b>',
  statusBadge(w.status),
  w.last_run_at ? new Date(w.last_run_at).toISOString().slice(0,16).replace('T',' ') : '-',
  w.hours_ago ? Math.round(Number(w.hours_ago)*10)/10+' h' : '-',
  '<code>'+w.max_silence+'</code>'
]));
const html = '<!DOCTYPE html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Workflows audit</title>' +
'<style>body{font-family:-apple-system,Arial,sans-serif;max-width:1100px;margin:24px auto;padding:16px;color:#1f2937;background:#f3f4f6}h1{color:#0f172a;margin:0 0 4px}.meta{color:#64748b;font-size:13px}table{width:100%;background:white;border-collapse:collapse;border-radius:8px;overflow:hidden}thead{background:#1f2937;color:white}thead th{padding:10px 8px;text-align:left;font-size:12px}.alert{background:#fee2e2;color:#991b1b;padding:12px;border-radius:6px;margin:12px 0}</style>' +
'</head><body>' +
'<a href="/webhook/admin-index" style="color:#2563eb;font-size:13px;text-decoration:none">← Admin index</a>' +
'<h1>Workflows audit</h1>' +
'<div class="meta">Manifest de 14 crons criticos. STALE = sin actividad en su ventana esperada. NEVER = nunca corrio. NO_TRACK = no loggea (mejorar).</div>' +
(stale.length > 0 ? '<div class="alert"><b>'+stale.length+' workflow(s) sin actividad reciente</b> — revisa si fueron desactivados.</div>' : '<div style="background:#d1fae5;color:#065f46;padding:12px;border-radius:6px;margin:12px 0"><b>Todos los crons activos</b></div>') +
'<table><thead><tr><th>Workflow</th><th>Status</th><th>Ultimo run</th><th>Hace</th><th>Max silence</th></tr></thead><tbody>'+rows.join('')+'</tbody></table>' +
'<p style="color:#94a3b8;font-size:11px;margin-top:32px;text-align:center">cron_workflow_audit hace este mismo check diario 07:30 y emite security_event si stale > 0.</p>' +
'</body></html>';
return [{ json: { html } }];
